function sortedArrayToBST(nums: number[]): TreeNode | null {
  const build = (lo: number, hi: number): TreeNode | null => {
    if (lo > hi) return null;
    const m = (lo + hi) >> 1;
    const n = new TreeNode(nums[m]);
    n.left = build(lo, m - 1);
    n.right = build(m + 1, hi);
    return n;
  };
  return build(0, nums.length - 1);
}
